@app.route("/screenshot", methods=["POST", "GET"])
def screenshot():
    data = request.get_json(silent=True) or {}
    url = request.args.get("url") or data.get("url")
    width = int(request.args.get("width") or data.get("width") or DEFAULT_WIDTH)
    height = int(request.args.get("height") or data.get("height") or DEFAULT_HEIGHT)
    if not url or not _url_allowed(url):
        return jsonify({"error": "invalid_or_disallowed_url"}), 400
    try:
        image_bytes, ctype, key = _get_or_create(url, width, height)
        if request.args.get("download") == "1":
            return send_file(io.BytesIO(image_bytes), mimetype=ctype, as_attachment=True, download_name=f"{uuid.uuid4().hex}.{SCREENSHOT_FORMAT}")
        if request.args.get("base64") == "1":
            return jsonify({"url": url, "content_type": ctype, "image_base64": base64.b64encode(image_bytes).decode("ascii"), "s3_key": key})
        return send_file(io.BytesIO(image_bytes), mimetype=ctype)
    except Exception as e:
        return jsonify({"error": "screenshot_failed", "detail": str(e)}), 500

@app.route("/preview", methods=["GET"])
def preview():
    url = request.args.get("url")
    if not url or not _url_allowed(url):
        return jsonify({"error": "invalid_or_disallowed_url"}), 400
    width = int(request.args.get("width") or DEFAULT_WIDTH)
    height = int(request.args.get("height") or DEFAULT_HEIGHT)
    try:
        image_bytes, ctype, key = _get_or_create(url, width, height)
        b64 = base64.b64encode(image_bytes).decode("ascii")
        return jsonify({
            "url": url,
            "content_type": ctype,
            "thumbnail_base64": b64,
            "s3_key": key,
            "width": width,
            "height": height,
        })
    except Exception as e:
        return jsonify({"error": "preview_failed", "detail": str(e)}), 500

